using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change #1: Discriminator property renamed from "Discriminator" to "$type".
            // Existing documents use "Discriminator", and direct SQL queries reference c.Discriminator.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2: id format changed from "Product|{key}" to "{key}".
            // Existing 500K documents use the old format — preserve it via custom generator.
            entity.Property<string>("__id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change #3: HasIndex now throws for Cosmos (was silently ignored).
            // Removed: entity.HasIndex(p => p.Sku);
        });
    }
}

